import React, { useState, useCallback, memo } from 'react';

const Child = memo(({ onIncrement }) => {
  console.log('Child komponent render olundu');
  return <button onClick={onIncrement}>Artır</button>;
});

function Parent() {
  const [count, setCount] = useState(0);

  const handleIncrement = useCallback(() => {
    setCount(c => c + 1);
  }, []); // Boş massiv – funksiya yalnız bir dəfə yaradılır

  return (
    <div>
      <p>Say: {count}</p>
      <Child onIncrement={handleIncrement} />
    </div>
  );
}

console.log('useCallback ilə funksiya memorizasiyası yaradıldı');

import React, { useState, useCallback } from 'react';

function Example() {
  const [count, setCount] = useState(0);
  const [step, setStep] = useState(1);

  const increment = useCallback(() => {
    setCount(c => c + step);
  }, [step]); // step dəyişəndə funksiya yenidən yaradılır

  return (
    <div>
      <p>Say: {count}</p>
      <button onClick={increment}>Artır ({step})</button>
      <button onClick={() => setStep(step + 1)}>Addımı artır</button>
    </div>
  );
}

console.log('Asılılıq massivi ilə useCallback yaradıldı');

